-- Generated from a fresh migrated ClickHouse instance.
-- Refresh the generated schema inventory from this bootstrap with:
--   python3 scripts/extract_clickhouse_bootstrap.py

CREATE DATABASE IF NOT EXISTS naap;

CREATE USER IF NOT EXISTS naap_writer
    IDENTIFIED WITH sha256_password BY '${CLICKHOUSE_WRITER_PASSWORD}'
    DEFAULT DATABASE naap;

GRANT INSERT, SELECT, CREATE TABLE, DROP TABLE, CREATE VIEW, DROP VIEW ON naap.* TO naap_writer;

CREATE USER IF NOT EXISTS naap_reader
    IDENTIFIED WITH sha256_password BY '${CLICKHOUSE_READER_PASSWORD}'
    DEFAULT DATABASE naap;

GRANT SELECT ON naap.* TO naap_reader;


CREATE TABLE naap.kafka_network_events (`id` String, `type` String, `timestamp` String, `gateway` String, `data` String) ENGINE = Kafka SETTINGS kafka_broker_list = '${KAFKA_BROKER_LIST}', kafka_topic_list = 'network_events', kafka_group_name = '${KAFKA_NETWORK_GROUP}', kafka_format = 'JSONEachRow', kafka_skip_broken_messages = 100, kafka_num_consumers = 6;

CREATE TABLE naap.kafka_streaming_events (`id` String, `type` String, `timestamp` String, `gateway` String, `data` String) ENGINE = Kafka SETTINGS kafka_broker_list = '${KAFKA_BROKER_LIST}', kafka_topic_list = 'streaming_events', kafka_group_name = '${KAFKA_STREAMING_GROUP}', kafka_format = 'JSONEachRow', kafka_skip_broken_messages = 100, kafka_num_consumers = 1;

CREATE TABLE naap.accepted_raw_events (`event_id` String, `event_type` LowCardinality(String), `event_subtype` LowCardinality(String) DEFAULT multiIf(event_type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), ''), `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `data` String, `source_topic` LowCardinality(String) DEFAULT '', `source_partition` Int32 DEFAULT 0, `source_offset` Int64 DEFAULT 0, `payload_hash` String DEFAULT hex(MD5(data)), `schema_version` Nullable(String) DEFAULT nullIf(JSONExtractString(data, 'schema_version'), ''), `ingested_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, event_type, event_ts, event_id) TTL toDateTime(event_ts) + toIntervalDay(90) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_discovery_latency_hourly (`hour` DateTime, `org` LowCardinality(String), `orch_address` String, `latency_ms_sum` UInt64, `sample_count` UInt64) ENGINE = SummingMergeTree PARTITION BY toYYYYMM(hour) ORDER BY (orch_address, org, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_fps_hourly (`hour` DateTime, `org` LowCardinality(String), `orch_address` String, `pipeline` LowCardinality(String), `inference_fps_sum` Float64, `input_fps_sum` Float64, `sample_count` UInt64) ENGINE = SummingMergeTree PARTITION BY toYYYYMM(hour) ORDER BY (orch_address, pipeline, org, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_orch_reliability_hourly (`hour` DateTime, `org` LowCardinality(String), `orch_address` String, `ai_stream_count` UInt64, `degraded_count` UInt64, `restart_count` UInt64, `error_count` UInt64) ENGINE = SummingMergeTree PARTITION BY toYYYYMM(hour) ORDER BY (orch_address, org, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_orch_state (`orch_address` String, `org` LowCardinality(String), `name` String, `uri` String, `version` String, `last_seen` DateTime64(3, 'UTC'), `raw_capabilities` String) ENGINE = ReplacingMergeTree(last_seen) ORDER BY orch_address SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_payment_hourly (`hour` DateTime, `org` LowCardinality(String), `pipeline` LowCardinality(String), `orch_address` String, `total_wei` UInt64, `event_count` UInt64) ENGINE = SummingMergeTree((total_wei, event_count)) PARTITION BY toYYYYMM(hour) ORDER BY (org, pipeline, orch_address, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_stream_hourly (`hour` DateTime, `org` LowCardinality(String), `pipeline` LowCardinality(String), `started` UInt64, `completed` UInt64, `no_orch` UInt64, `orch_swap` UInt64) ENGINE = SummingMergeTree PARTITION BY toYYYYMM(hour) ORDER BY (org, pipeline, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_stream_state (`stream_id` String, `org` LowCardinality(String), `pipeline` LowCardinality(String), `state` LowCardinality(String), `last_seen` DateTime64(3, 'UTC'), `started_at` DateTime64(3, 'UTC'), `is_closed` UInt8, `has_failure` UInt8, `orch_address` String) ENGINE = ReplacingMergeTree(last_seen) ORDER BY stream_id SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_stream_status_samples (`sample_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `stream_id` String, `gateway` String, `orch_address` String, `pipeline` LowCardinality(String), `state` LowCardinality(String), `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Float64, `is_attributed` UInt8) ENGINE = MergeTree PARTITION BY toYYYYMM(sample_ts) ORDER BY (org, stream_id, sample_ts) TTL toDateTime(sample_ts) + toIntervalDay(30) SETTINGS index_granularity = 8192;

CREATE TABLE naap.agg_webrtc_hourly (`hour` DateTime, `org` LowCardinality(String), `stream_id` String, `video_jitter_sum` Float64, `video_packets_lost` UInt64, `video_packets_recv` UInt64, `audio_jitter_sum` Float64, `audio_packets_lost` UInt64, `audio_packets_recv` UInt64, `sample_count` UInt64, `quality_good` UInt64, `quality_fair` UInt64, `quality_poor` UInt64) ENGINE = SummingMergeTree PARTITION BY toYYYYMM(hour) ORDER BY (org, stream_id, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_streaming_gpu_metrics_hourly_store (`window_start` DateTime('UTC'), `org` LowCardinality(String), `orchestrator_address` String, `pipeline_id` String, `model_id` Nullable(String), `gpu_id` Nullable(String), `region` Nullable(String), `avg_output_fps` Float64, `output_fps_sum` Float64, `p95_output_fps` Float64, `output_fps_p95_state` AggregateFunction(quantileTDigest(0.95), Float64), `fps_jitter_coefficient` Nullable(Float64), `status_samples` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String), `avg_prompt_to_first_frame_ms` Nullable(Float64), `prompt_to_first_frame_sum_ms` Float64, `avg_startup_latency_ms` Nullable(Float64), `startup_latency_sum_ms` Float64, `avg_e2e_latency_ms` Nullable(Float64), `e2e_latency_sum_ms` Float64, `p95_prompt_to_first_frame_latency_ms` Nullable(Float64), `prompt_to_first_frame_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `p95_startup_latency_ms` Nullable(Float64), `startup_latency_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `p95_e2e_latency_ms` Nullable(Float64), `e2e_latency_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `prompt_to_first_frame_sample_count` UInt64, `startup_latency_sample_count` UInt64, `e2e_latency_sample_count` UInt64, `known_sessions_count` UInt64, `startup_success_sessions` UInt64, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64, `startup_failed_sessions` UInt64 DEFAULT 0, `startup_unexcused_sessions` UInt64, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `startup_failed_rate` Float64 DEFAULT 0, `startup_unexcused_rate` Float64, `swap_rate` Float64, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, window_start, orchestrator_address, pipeline_id, ifNull(model_id, ''), ifNull(gpu_id, ''), refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_streaming_demand_hourly_store (`window_start` DateTime('UTC'), `org` LowCardinality(String), `gateway` String, `region` Nullable(String), `pipeline_id` String, `model_id` Nullable(String), `sessions_count` UInt64, `avg_output_fps` Float64, `output_fps_sum` Float64, `status_samples` UInt64, `total_minutes` Float64, `known_sessions_count` UInt64, `requested_sessions` UInt64 DEFAULT 0, `startup_success_sessions` UInt64 DEFAULT 0, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64 DEFAULT 0, `startup_failed_sessions` UInt64 DEFAULT 0, `loading_only_sessions` UInt64 DEFAULT 0, `zero_output_fps_sessions` UInt64 DEFAULT 0, `effective_failed_sessions` UInt64 DEFAULT 0, `served_sessions` UInt64, `unserved_sessions` UInt64, `total_demand_sessions` UInt64, `startup_unexcused_sessions` UInt64, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `startup_success_rate` Float64, `excused_failure_rate` Float64 DEFAULT 0, `effective_success_rate` Float64, `ticket_face_value_eth` Float64, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, window_start, gateway, pipeline_id, ifNull(model_id, ''), refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_streaming_sla_input_hourly_store (`window_start` DateTime('UTC'), `org` LowCardinality(String), `orchestrator_address` String, `pipeline_id` String, `model_id` Nullable(String), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String) DEFAULT CAST(NULL, 'Nullable(String)'), `region` Nullable(String), `known_sessions_count` UInt64, `requested_sessions` UInt64 DEFAULT 0, `startup_success_sessions` UInt64, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64, `startup_failed_sessions` UInt64 DEFAULT 0, `loading_only_sessions` UInt64 DEFAULT 0, `zero_output_fps_sessions` UInt64 DEFAULT 0, `output_failed_sessions` UInt64 DEFAULT 0, `effective_failed_sessions` UInt64 DEFAULT 0, `startup_unexcused_sessions` UInt64, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `startup_success_rate` Nullable(Float64), `excused_failure_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `effective_success_rate` Nullable(Float64), `no_swap_rate` Nullable(Float64), `output_viability_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `output_fps_sum` Float64 DEFAULT 0, `status_samples` UInt64 DEFAULT 0, `prompt_to_first_frame_sum_ms` Float64 DEFAULT 0, `prompt_to_first_frame_sample_count` UInt64 DEFAULT 0, `e2e_latency_sum_ms` Float64 DEFAULT 0, `e2e_latency_sample_count` UInt64 DEFAULT 0, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, window_start, orchestrator_address, pipeline_id, ifNull(model_id, ''), ifNull(gpu_id, ''), refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_streaming_sla_hourly_store (`window_start` DateTime('UTC'), `org` Nullable(String) DEFAULT CAST(NULL, 'Nullable(String)'), `orchestrator_address` String, `pipeline_id` String, `model_id` Nullable(String), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String) DEFAULT CAST(NULL, 'Nullable(String)'), `region` Nullable(String), `known_sessions_count` UInt64, `requested_sessions` UInt64 DEFAULT 0, `startup_success_sessions` UInt64, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64, `startup_failed_sessions` UInt64 DEFAULT 0, `loading_only_sessions` UInt64 DEFAULT 0, `zero_output_fps_sessions` UInt64 DEFAULT 0, `output_failed_sessions` UInt64 DEFAULT 0, `effective_failed_sessions` UInt64 DEFAULT 0, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `startup_success_rate` Nullable(Float64), `excused_failure_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `effective_success_rate` Nullable(Float64), `no_swap_rate` Nullable(Float64), `output_viability_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `output_fps_sum` Float64 DEFAULT 0, `status_samples` UInt64 DEFAULT 0, `avg_output_fps` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `prompt_to_first_frame_sum_ms` Float64 DEFAULT 0, `prompt_to_first_frame_sample_count` UInt64 DEFAULT 0, `avg_prompt_to_first_frame_ms` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `e2e_latency_sum_ms` Float64 DEFAULT 0, `e2e_latency_sample_count` UInt64 DEFAULT 0, `avg_e2e_latency_ms` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `reliability_score` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `ptff_score` Float64 DEFAULT 0, `e2e_score` Float64 DEFAULT 0, `latency_score` Float64 DEFAULT 0, `fps_score` Float64 DEFAULT 0, `quality_score` Float64 DEFAULT 0, `sla_semantics_version` String DEFAULT '', `sla_score` Nullable(Float64), `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(window_start) ORDER BY (window_start, orchestrator_address, pipeline_id, ifNull(model_id, ''), ifNull(gpu_id, ''), ifNull(region, ''), refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_active_stream_state_latest_store (`canonical_session_key` String, `event_id` String, `sample_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `stream_id` String, `request_id` String, `gateway` String, `pipeline` String, `model_id` Nullable(String), `orch_address` Nullable(String), `attribution_status` String, `attribution_reason` String, `state` String, `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Nullable(Float64), `started_at` Nullable(DateTime64(3, 'UTC')), `last_seen` DateTime64(3, 'UTC'), `completed` UInt8, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(sample_ts)) ORDER BY (canonical_session_key, refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE IF NOT EXISTS naap.canonical_ai_batch_job_store (`request_id` String, `org` LowCardinality(String), `gateway` String, `pipeline` LowCardinality(String), `model_id` String, `received_at` Nullable(DateTime64(3, 'UTC')), `completed_at` DateTime64(3, 'UTC'), `success` Nullable(UInt8), `tries` UInt16, `duration_ms` Int64, `orch_url` String, `orch_url_norm` String, `selection_outcome` LowCardinality(String) DEFAULT 'unknown', `latency_score` Float64, `price_per_unit` Float64, `error_type` String, `error` String, `attribution_status` LowCardinality(String), `attribution_reason` LowCardinality(String), `attribution_method` LowCardinality(String), `attribution_confidence` LowCardinality(String), `attributed_orch_uri` Nullable(String), `capability_version_id` Nullable(String), `attribution_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `attributed_model` Nullable(String), `resolver_run_id` String DEFAULT '', `materialized_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(materialized_at) PARTITION BY (org, toYYYYMM(completed_at)) ORDER BY (org, request_id, completed_at) TTL toDateTime(completed_at) + toIntervalDay(90) SETTINGS index_granularity = 8192;

CREATE TABLE IF NOT EXISTS naap.canonical_byoc_job_store (`event_id` String, `org` LowCardinality(String), `gateway` String, `capability` String, `completed_at` DateTime64(3, 'UTC'), `success` Nullable(UInt8), `duration_ms` Int64, `http_status` UInt16, `orch_address` String, `orch_url` String, `orch_url_norm` String, `selection_outcome` LowCardinality(String) DEFAULT 'unknown', `worker_url` String, `charged_compute` UInt8, `error` String, `model` Nullable(String), `price_per_unit` Float64, `attribution_status` LowCardinality(String), `attribution_reason` LowCardinality(String), `attribution_method` LowCardinality(String), `attribution_confidence` LowCardinality(String), `attributed_orch_uri` Nullable(String), `capability_version_id` Nullable(String), `attribution_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `resolver_run_id` String DEFAULT '', `materialized_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(materialized_at) PARTITION BY (org, toYYYYMM(completed_at)) ORDER BY (org, event_id, completed_at) TTL toDateTime(completed_at) + toIntervalDay(90) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_snapshots_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_name` String, `orch_uri` String, `orch_uri_norm` String, `version` String, `raw_capabilities` String) ENGINE = ReplacingMergeTree(snapshot_ts) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (org, snapshot_ts, orch_address, orch_uri_norm, snapshot_row_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_hardware_inventory (`snapshot_row_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `pipeline_id` String, `model_id` String, `gpu_id` String, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String)) ENGINE = ReplacingMergeTree(snapshot_ts) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (org, orch_address, pipeline_id, model_id, gpu_id, snapshot_row_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_hardware_inventory_by_snapshot (`snapshot_row_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `pipeline_id` String, `model_id` String, `gpu_id` String, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String)) ENGINE = ReplacingMergeTree(snapshot_ts) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (snapshot_row_id, pipeline_id, model_id, gpu_id, org) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_offer_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `offered_name` Nullable(String), `model_id` Nullable(String), `warm` Nullable(UInt8), `advertised_capacity` Nullable(Int32), `hardware_present` UInt8, `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64)) ENGINE = ReplacingMergeTree(snapshot_ts) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (org, snapshot_ts, orch_address, ifNull(model_id, ''), ifNull(gpu_id, ''), snapshot_row_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_pricing_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `constraint_value` Nullable(String), `price_per_unit` Int64, `pixels_per_unit` Int64) ENGINE = ReplacingMergeTree(snapshot_ts) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (org, snapshot_ts, orch_address, ifNull(capability_id, toUInt16(0)), ifNull(constraint_value, ''), snapshot_row_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_capability_snapshot_latest (`org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `snapshot_row_id` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `source_event_id` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `snapshot_ts` AggregateFunction(max, DateTime64(3, 'UTC')), `orch_name` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `orch_uri` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `version` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `raw_capabilities` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8)) ENGINE = AggregatingMergeTree PARTITION BY org ORDER BY (org, orch_address, orch_uri_norm) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_orch_capability_intervals (`capability_version_id` String, `org` LowCardinality(String), `orch_address` String, `orch_uri` Nullable(String), `orch_uri_norm` String, `valid_from_ts` DateTime64(3, 'UTC'), `valid_to_ts` Nullable(DateTime64(3, 'UTC')), `canonical_pipeline` Nullable(String), `canonical_model` Nullable(String), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `hardware_present` UInt8, `interval_hash` String, `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `built_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(built_at) PARTITION BY (org, toYYYYMM(valid_from_ts)) ORDER BY (org, orch_address, valid_from_ts, capability_version_id, ifNull(canonical_pipeline, ''), ifNull(canonical_model, ''), ifNull(gpu_id, '')) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_orch_capability_versions (`capability_version_id` String, `org` LowCardinality(String), `orch_address` String, `orch_uri` Nullable(String), `orch_uri_norm` String, `local_address` Nullable(String), `snapshot_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `capability_payload_hash` String, `raw_capabilities` String, `is_noop` UInt8, `version_rank` UInt32, `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `built_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(built_at) PARTITION BY (org, toYYYYMM(snapshot_ts)) ORDER BY (org, orch_address, orch_uri_norm, snapshot_ts, capability_version_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_payment_links_store (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `session_id` String, `request_id` String, `manifest_id` String, `pipeline_hint` String, `sender_address` String, `recipient_address` String, `orchestrator_url` String, `face_value_wei` UInt64, `price_wei_per_pixel` Float64, `win_prob` Float64, `num_tickets` UInt64, `canonical_session_key` Nullable(String), `link_method` LowCardinality(String), `link_status` LowCardinality(String), `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(refreshed_at) PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, toStartOfHour(event_ts), event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_selection_attribution_current (`selection_event_id` String, `org` LowCardinality(String), `canonical_session_key` String, `selection_ts` DateTime64(3, 'UTC'), `attribution_status` LowCardinality(String), `attribution_reason` LowCardinality(String), `attribution_method` LowCardinality(String), `selection_confidence` LowCardinality(String), `selected_capability_version_id` Nullable(String), `selected_snapshot_event_id` Nullable(String), `selected_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `attributed_orch_address` Nullable(String), `attributed_orch_uri` Nullable(String), `canonical_pipeline` Nullable(String), `canonical_model` Nullable(String), `gpu_id` Nullable(String), `decision_input_hash` String DEFAULT '', `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `decided_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(decided_at) PARTITION BY org ORDER BY (org, selection_event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_selection_attribution_decisions (`decision_id` String, `selection_event_id` String, `org` LowCardinality(String), `canonical_session_key` String, `selection_ts` DateTime64(3, 'UTC'), `attribution_status` LowCardinality(String), `attribution_reason` LowCardinality(String), `attribution_method` LowCardinality(String), `selection_confidence` LowCardinality(String), `selected_capability_version_id` Nullable(String), `selected_snapshot_event_id` Nullable(String), `selected_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `attributed_orch_address` Nullable(String), `attributed_orch_uri` Nullable(String), `canonical_pipeline` Nullable(String), `canonical_model` Nullable(String), `gpu_id` Nullable(String), `decision_input_hash` String DEFAULT '', `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `decided_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(selection_ts)) ORDER BY (org, selection_event_id, decided_at, decision_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_selection_events (`selection_event_id` String, `org` LowCardinality(String), `canonical_session_key` String, `selection_seq` UInt32, `selection_ts` DateTime64(3, 'UTC'), `selection_trigger` LowCardinality(String), `observed_orch_raw_address` Nullable(String), `observed_orch_url` Nullable(String), `observed_model_hint` Nullable(String), `observed_pipeline_hint` Nullable(String), `anchor_event_id` String, `anchor_event_type` LowCardinality(String), `anchor_event_ts` DateTime64(3, 'UTC'), `source_topic` LowCardinality(String) DEFAULT '', `source_partition` Int32 DEFAULT 0, `source_offset` Int64 DEFAULT 0, `selection_input_hash` String DEFAULT '', `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `rebuilt_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(rebuilt_at) PARTITION BY (org, toYYYYMM(selection_ts)) ORDER BY (org, canonical_session_key, selection_event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_session_current_store (`canonical_session_key` String, `org` LowCardinality(String), `stream_id` String, `request_id` String, `current_selection_event_id` Nullable(String), `current_selection_ts` Nullable(DateTime64(3, 'UTC')), `canonical_pipeline` String, `canonical_model` Nullable(String), `gpu_id` Nullable(String), `started_at` Nullable(DateTime64(3, 'UTC')), `last_seen` DateTime64(3, 'UTC'), `startup_latency_ms` Nullable(Float64), `e2e_latency_ms` Nullable(Float64), `prompt_to_playable_latency_ms` Nullable(Float64), `requested_seen` UInt8 DEFAULT 0, `started` UInt8, `playable_seen` UInt8, `selection_outcome` LowCardinality(String) DEFAULT 'unknown', `no_orch` UInt8, `completed` UInt8, `swap_count` UInt64, `restart_seen` UInt8, `error_seen` UInt8, `degraded_input_seen` UInt8, `degraded_inference_seen` UInt8, `status_sample_count` UInt64, `status_error_sample_count` UInt64, `startup_error_count` UInt64 DEFAULT 0, `excusable_error_count` UInt64 DEFAULT 0, `loading_only_session` UInt8, `zero_output_fps_session` UInt8, `health_signal_count` UInt64, `health_expected_signal_count` UInt64, `health_signal_coverage_ratio` Float64, `startup_outcome` LowCardinality(String), `excusal_reason` LowCardinality(String) DEFAULT 'none', `has_ambiguous_identity` UInt8, `has_snapshot_match` UInt8, `is_hardware_less` UInt8, `is_stale` UInt8, `attribution_reason` LowCardinality(String), `attribution_status` LowCardinality(String), `attributed_orch_address` Nullable(String), `attributed_orch_uri` Nullable(String), `attribution_snapshot_ts` Nullable(DateTime64(3, 'UTC')), `resolver_version` String DEFAULT '', `resolver_run_id` String DEFAULT '', `materialized_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(materialized_at) PARTITION BY (org, toYYYYMM(last_seen)) ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_session_demand_input_current (`canonical_session_key` String, `window_start` DateTime('UTC'), `org` LowCardinality(String), `gateway` String, `region` Nullable(String), `pipeline_id` String, `model_id` Nullable(String), `requested_seen` UInt8 DEFAULT 0, `selection_outcome` LowCardinality(String) DEFAULT 'unknown', `startup_outcome` LowCardinality(String), `excusal_reason` LowCardinality(String) DEFAULT 'none', `loading_only_session` UInt8 DEFAULT 0, `zero_output_fps_session` UInt8 DEFAULT 0, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `swap_count` UInt64, `error_seen` UInt8, `status_error_sample_count` UInt64, `health_signal_coverage_ratio` Float64, `avg_output_fps` Float64, `total_minutes` Float64, `ticket_face_value_eth` Float64, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(refreshed_at) PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_status_hours_store (`canonical_session_key` String, `org` LowCardinality(String), `hour` DateTime('UTC'), `stream_id` String, `request_id` String, `canonical_pipeline` String, `canonical_model` Nullable(String), `orch_address` Nullable(String), `attribution_status` LowCardinality(String), `attribution_reason` LowCardinality(String), `started_at` Nullable(DateTime64(3, 'UTC')), `session_last_seen` DateTime64(3, 'UTC'), `startup_latency_ms` Nullable(Float64), `status_samples` UInt64, `fps_positive_samples` UInt64, `running_state_samples` UInt64, `degraded_input_samples` UInt64, `degraded_inference_samples` UInt64, `error_samples` UInt64, `avg_output_fps` Float64, `avg_input_fps` Float64, `avg_e2e_latency_ms` Nullable(Float64), `prompt_to_playable_latency_ms` Nullable(Float64), `is_terminal_tail_artifact` UInt8, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(hour)) ORDER BY (canonical_session_key, hour, refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.canonical_status_samples_recent_store (`canonical_session_key` String, `event_id` String, `sample_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `stream_id` String, `request_id` String, `gateway` String, `orch_address` Nullable(String), `pipeline` String, `model_id` Nullable(String), `attribution_status` String, `attribution_reason` String, `state` String, `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Nullable(Float64), `is_attributed` UInt8, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64(), PROJECTION by_refresh_run_session (SELECT refresh_run_id, canonical_session_key, sample_ts, gateway, output_fps, org, stream_id, request_id, orch_address, pipeline, model_id, attribution_status, attribution_reason, state, input_fps, e2e_latency_ms, event_id ORDER BY refresh_run_id, canonical_session_key, sample_ts)) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(sample_ts)) ORDER BY (event_id, refreshed_at) SETTINGS index_granularity = 8192;

CREATE TABLE naap.gateway_metadata (`eth_address` LowCardinality(String), `name` String, `avatar` String, `deposit` Float64, `reserve` Float64, `updated_at` DateTime) ENGINE = ReplacingMergeTree(updated_at) ORDER BY eth_address TTL updated_at + toIntervalDay(7) SETTINGS index_granularity = 8192;

CREATE TABLE naap.ignored_raw_events (`event_id` String, `event_type` LowCardinality(String), `event_subtype` LowCardinality(String) DEFAULT multiIf(event_type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), ''), `ignore_reason` LowCardinality(String), `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `data` String, `source_topic` LowCardinality(String) DEFAULT '', `source_partition` Int32 DEFAULT 0, `source_offset` Int64 DEFAULT 0, `payload_hash` String DEFAULT hex(MD5(data)), `schema_version` Nullable(String) DEFAULT nullIf(JSONExtractString(data, 'schema_version'), ''), `ingested_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, ignore_reason, event_type, event_ts, event_id) TTL toDateTime(event_ts) + toIntervalDay(90) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_ai_stream_events (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `raw_pipeline_hint` String, `event_name` LowCardinality(String), `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `message` String, `data` String) ENGINE = ReplacingMergeTree(event_ts) PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, canonical_session_key, event_ts, event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_ai_stream_status (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `raw_pipeline_hint` String, `state` LowCardinality(String), `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Float64, `start_time` Nullable(DateTime64(3, 'UTC')), `restart_count` UInt64, `last_error` String, `last_error_ts` DateTime64(3, 'UTC'), `data` String) ENGINE = ReplacingMergeTree(event_ts) PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, canonical_session_key, event_ts, event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_network_capabilities (`row_id` String, `event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_name` String, `orch_uri` String, `orch_uri_norm` String, `version` String, `raw_capabilities` String) ENGINE = ReplacingMergeTree(event_ts) PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, orch_address, orch_uri_norm, event_ts, row_id) SETTINGS index_granularity = 8192;

