CREATE TABLE naap.normalized_session_event_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `event_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `any_event_message_count_state` AggregateFunction(sum, UInt64), `event_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) ENGINE = AggregatingMergeTree PARTITION BY org ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_session_orchestrator_observation_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observation_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) ENGINE = AggregatingMergeTree PARTITION BY org ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_session_status_hour_rollup (`org` LowCardinality(String), `canonical_session_key` String, `hour` DateTime('UTC'), `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `status_samples_state` AggregateFunction(sum, UInt64), `fps_positive_samples_state` AggregateFunction(sum, UInt64), `running_state_samples_state` AggregateFunction(sum, UInt64), `degraded_input_samples_state` AggregateFunction(sum, UInt64), `degraded_inference_samples_state` AggregateFunction(sum, UInt64), `error_samples_state` AggregateFunction(sum, UInt64), `output_fps_sum_state` AggregateFunction(sum, Float64), `input_fps_sum_state` AggregateFunction(sum, Float64), `e2e_latency_sum_state` AggregateFunction(sum, Float64), `e2e_latency_count_state` AggregateFunction(sum, UInt64)) ENGINE = AggregatingMergeTree PARTITION BY (org, toYYYYMM(hour)) ORDER BY (org, canonical_session_key, hour) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_session_status_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `canonical_pipeline_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `start_time_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `restart_seen_count_state` AggregateFunction(sum, UInt64), `error_seen_count_state` AggregateFunction(sum, UInt64), `degraded_input_seen_count_state` AggregateFunction(sum, UInt64), `degraded_inference_seen_count_state` AggregateFunction(sum, UInt64), `status_sample_count_state` AggregateFunction(sum, UInt64), `status_error_sample_count_state` AggregateFunction(sum, UInt64), `online_seen_count_state` AggregateFunction(sum, UInt64), `positive_output_seen_count_state` AggregateFunction(sum, UInt64), `running_state_samples_count_state` AggregateFunction(sum, UInt64), `status_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) ENGINE = AggregatingMergeTree PARTITION BY org ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_session_trace_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `pipeline_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `raw_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `started_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `first_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `few_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `first_ingest_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `runner_first_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `started_count_state` AggregateFunction(sum, UInt64), `playable_seen_count_state` AggregateFunction(sum, UInt64), `no_orch_count_state` AggregateFunction(sum, UInt64), `completed_count_state` AggregateFunction(sum, UInt64), `swap_count_state` AggregateFunction(sum, UInt64), `trace_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) ENGINE = AggregatingMergeTree PARTITION BY org ORDER BY (org, canonical_session_key) SETTINGS index_granularity = 8192;

CREATE TABLE naap.normalized_stream_trace (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `trace_type` LowCardinality(String), `raw_pipeline_hint` String, `pipeline_id` String, `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `message` String, `data` String) ENGINE = ReplacingMergeTree(event_ts) PARTITION BY (org, toYYYYMM(event_ts)) ORDER BY (org, canonical_session_key, event_ts, event_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.orch_metadata (`eth_address` LowCardinality(String), `name` String, `service_uri` String, `avatar` String, `total_stake` Float64, `reward_cut` Float64, `fee_cut` Float64, `activation_status` UInt8, `updated_at` DateTime) ENGINE = ReplacingMergeTree(updated_at) ORDER BY eth_address TTL updated_at + toIntervalDay(7) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_backfill_runs (`run_id` String, `owner_id` String, `org` LowCardinality(String), `event_date` Date, `hash_range_start` Nullable(UInt32), `hash_range_end` Nullable(UInt32), `status` LowCardinality(String), `cutoff_ts` Nullable(DateTime64(3, 'UTC')), `rows_processed` UInt64 DEFAULT 0, `mismatch_count` UInt64 DEFAULT 0, `error_summary` Nullable(String), `started_at` DateTime64(3, 'UTC'), `finished_at` Nullable(DateTime64(3, 'UTC')), `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(event_date) ORDER BY (org, event_date, ifNull(hash_range_start, 0), run_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dead_letters (`dead_letter_id` String, `item_type` LowCardinality(String), `item_id` String, `org` Nullable(String), `earliest_affected_ts` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32 DEFAULT 0, `next_retry_at` Nullable(DateTime64(3, 'UTC')), `last_error_summary` String, `resolver_version` String DEFAULT '', `escalated` UInt8 DEFAULT 0, `created_at` DateTime64(3, 'UTC') DEFAULT now64(), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (item_type, item_id, dead_letter_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dirty_orchestrators (`work_item_id` String, `orch_identity` String, `org` LowCardinality(String), `reason` LowCardinality(String), `earliest_affected_ts` Nullable(DateTime64(3, 'UTC')), `claim_owner` Nullable(String), `lease_acquired_at` Nullable(DateTime64(3, 'UTC')), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32 DEFAULT 0, `next_retry_at` Nullable(DateTime64(3, 'UTC')), `last_error_summary` Nullable(String), `resolver_version` String DEFAULT '', `created_at` DateTime64(3, 'UTC') DEFAULT now64(), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (org, orch_identity, work_item_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dirty_partitions (`org` LowCardinality(String), `event_date` Date, `status` LowCardinality(String), `reason` LowCardinality(String), `first_dirty_at` DateTime64(3, 'UTC'), `last_dirty_at` DateTime64(3, 'UTC'), `claim_owner` Nullable(String), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32, `last_error_summary` Nullable(String), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(event_date) ORDER BY (org, event_date) TTL toDateTime(event_date) + toIntervalDay(30) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dirty_windows (`org` LowCardinality(String), `window_start` DateTime64(3, 'UTC'), `window_end` DateTime64(3, 'UTC'), `status` LowCardinality(String), `reason` LowCardinality(String), `first_dirty_at` DateTime64(3, 'UTC'), `last_dirty_at` DateTime64(3, 'UTC'), `claim_owner` Nullable(String), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32, `last_error_summary` Nullable(String), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(window_start) ORDER BY (org, window_start, window_end) TTL toDateTime(window_start) + toIntervalDay(30) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dirty_selection_events (`work_item_id` String, `selection_event_id` String, `org` LowCardinality(String), `canonical_session_key` String, `reason` LowCardinality(String), `earliest_affected_ts` Nullable(DateTime64(3, 'UTC')), `claim_owner` Nullable(String), `lease_acquired_at` Nullable(DateTime64(3, 'UTC')), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32 DEFAULT 0, `next_retry_at` Nullable(DateTime64(3, 'UTC')), `last_error_summary` Nullable(String), `resolver_version` String DEFAULT '', `created_at` DateTime64(3, 'UTC') DEFAULT now64(), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (org, selection_event_id, work_item_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_dirty_sessions (`work_item_id` String, `canonical_session_key` String, `org` LowCardinality(String), `reason` LowCardinality(String), `earliest_affected_ts` Nullable(DateTime64(3, 'UTC')), `claim_owner` Nullable(String), `lease_acquired_at` Nullable(DateTime64(3, 'UTC')), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32 DEFAULT 0, `next_retry_at` Nullable(DateTime64(3, 'UTC')), `last_error_summary` Nullable(String), `resolver_version` String DEFAULT '', `created_at` DateTime64(3, 'UTC') DEFAULT now64(), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (org, canonical_session_key, work_item_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_query_event_ids (`query_id` String, `event_id` String, `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(created_at) ORDER BY (query_id, event_id) TTL toDateTime(created_at) + toIntervalDay(1) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_query_identities (`query_id` String, `identity` String, `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(created_at) ORDER BY (query_id, identity) TTL toDateTime(created_at) + toIntervalDay(1) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_query_selection_event_ids (`query_id` String, `selection_event_id` String, `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(created_at) ORDER BY (query_id, selection_event_id) TTL toDateTime(created_at) + toIntervalDay(1) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_query_session_keys (`query_id` String, `org` LowCardinality(String), `canonical_session_key` String, `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(created_at) ORDER BY (query_id, org, canonical_session_key) TTL toDateTime(created_at) + toIntervalDay(1) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_query_window_slices (`query_id` String, `org` LowCardinality(String), `window_start` DateTime('UTC'), `created_at` DateTime('UTC') DEFAULT now()) ENGINE = MergeTree ORDER BY (query_id, org, window_start, created_at) TTL created_at + toIntervalDay(2) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_runs (`run_id` String, `mode` LowCardinality(String), `status` LowCardinality(String), `owner_id` String, `org` Nullable(String), `window_start` Nullable(DateTime64(3, 'UTC')), `window_end` Nullable(DateTime64(3, 'UTC')), `cutoff_ts` Nullable(DateTime64(3, 'UTC')), `lateness_window_seconds` UInt64 DEFAULT 0, `dirty_quiet_period_seconds` UInt64 DEFAULT 0, `rows_processed` UInt64 DEFAULT 0, `mismatch_count` UInt64 DEFAULT 0, `error_summary` Nullable(String), `resolver_version` String DEFAULT '', `started_at` DateTime64(3, 'UTC'), `finished_at` Nullable(DateTime64(3, 'UTC')), `created_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(started_at) ORDER BY (started_at, run_id) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_repair_requests (`request_id` String, `org` Nullable(String), `window_start` DateTime64(3, 'UTC'), `window_end` DateTime64(3, 'UTC'), `status` LowCardinality(String), `requested_by` String, `reason` String, `dry_run` UInt8 DEFAULT 0, `claim_owner` Nullable(String), `lease_expires_at` Nullable(DateTime64(3, 'UTC')), `attempt_count` UInt32 DEFAULT 0, `started_at` Nullable(DateTime64(3, 'UTC')), `finished_at` Nullable(DateTime64(3, 'UTC')), `last_error_summary` Nullable(String), `created_at` DateTime64(3, 'UTC') DEFAULT now64(), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (ifNull(org, ''), window_start, request_id) TTL toDateTime(created_at) + toIntervalDay(30) SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_runtime_state (`state_key` String, `last_ingested_at` DateTime64(3, 'UTC'), `last_event_id` String, `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) ORDER BY state_key SETTINGS index_granularity = 8192;

CREATE TABLE naap.resolver_window_claims (`claim_key` String, `claim_type` LowCardinality(String), `mode` LowCardinality(String), `owner_id` String, `org` Nullable(String), `window_start` DateTime64(3, 'UTC'), `window_end` DateTime64(3, 'UTC'), `lease_expires_at` DateTime64(3, 'UTC'), `released_at` Nullable(DateTime64(3, 'UTC')), `created_at` DateTime64(3, 'UTC'), `updated_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = ReplacingMergeTree(updated_at) PARTITION BY toYYYYMM(created_at) ORDER BY (claim_type, ifNull(org, ''), window_start, window_end, claim_key) TTL toDateTime(created_at) + toIntervalDay(7) SETTINGS index_granularity = 8192;

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_snapshots_store TO naap.canonical_capability_snapshots_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_name` String, `orch_uri` String, `orch_uri_norm` String, `version` String, `raw_capabilities` String) AS SELECT row_id AS snapshot_row_id, event_id AS source_event_id, event_ts AS snapshot_ts, org, orch_address, orch_name, orch_uri, orch_uri_norm, version, raw_capabilities FROM naap.normalized_network_capabilities WHERE (row_id != '') AND (orch_address != '');

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_hardware_inventory TO naap.canonical_capability_hardware_inventory (`snapshot_row_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `pipeline_id` String, `model_id` String, `gpu_id` String, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String)) AS SELECT row_id AS snapshot_row_id, event_ts AS snapshot_ts, org, orch_address, orch_uri_norm, pipeline_id, model_id, JSONExtractString(gpu_json, 'id') AS gpu_id, nullIf(JSONExtractString(gpu_json, 'name'), '') AS gpu_model_name, nullIf(JSONExtractUInt(gpu_json, 'memory_total'), 0) AS gpu_memory_bytes_total, CAST(NULL, 'Nullable(String)') AS runner_version, CAST(NULL, 'Nullable(String)') AS cuda_version FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, JSONExtractString(hardware_json, 'pipeline') AS pipeline_id, JSONExtractString(hardware_json, 'model_id') AS model_id, arrayJoin(if(gpu_info_raw IN ('', 'null', '{}', '[]'), CAST([], 'Array(String)'), if(startsWith(gpu_info_raw, '['), JSONExtractArrayRaw(gpu_info_raw), tupleElement(JSONExtractKeysAndValuesRaw(gpu_info_raw), 2)))) AS gpu_json FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, hardware_json, JSONExtractRaw(hardware_json, 'gpu_info') AS gpu_info_raw FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, arrayJoin(JSONExtractArrayRaw(raw_capabilities, 'hardware')) AS hardware_json FROM naap.normalized_network_capabilities WHERE length(JSONExtractArrayRaw(raw_capabilities, 'hardware')) > 0))) WHERE (pipeline_id != '') AND (JSONExtractString(gpu_json, 'id') != '');

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_hardware_inventory_by_snapshot TO naap.canonical_capability_hardware_inventory_by_snapshot (`snapshot_row_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `pipeline_id` String, `model_id` String, `gpu_id` String, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String)) AS SELECT row_id AS snapshot_row_id, event_ts AS snapshot_ts, org, orch_address, orch_uri_norm, pipeline_id, model_id, JSONExtractString(gpu_json, 'id') AS gpu_id, nullIf(JSONExtractString(gpu_json, 'name'), '') AS gpu_model_name, nullIf(JSONExtractUInt(gpu_json, 'memory_total'), 0) AS gpu_memory_bytes_total, CAST(NULL, 'Nullable(String)') AS runner_version, CAST(NULL, 'Nullable(String)') AS cuda_version FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, JSONExtractString(hardware_json, 'pipeline') AS pipeline_id, JSONExtractString(hardware_json, 'model_id') AS model_id, arrayJoin(if(gpu_info_raw IN ('', 'null', '{}', '[]'), CAST([], 'Array(String)'), if(startsWith(gpu_info_raw, '['), JSONExtractArrayRaw(gpu_info_raw), tupleElement(JSONExtractKeysAndValuesRaw(gpu_info_raw), 2)))) AS gpu_json FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, hardware_json, JSONExtractRaw(hardware_json, 'gpu_info') AS gpu_info_raw FROM (SELECT row_id, event_ts, org, orch_address, orch_uri_norm, arrayJoin(JSONExtractArrayRaw(raw_capabilities, 'hardware')) AS hardware_json FROM naap.normalized_network_capabilities WHERE length(JSONExtractArrayRaw(raw_capabilities, 'hardware')) > 0))) WHERE (pipeline_id != '') AND (JSONExtractString(gpu_json, 'id') != '');

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_offer_inventory_store_builtin TO naap.canonical_capability_offer_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `offered_name` Nullable(String), `model_id` Nullable(String), `warm` Nullable(UInt8), `advertised_capacity` Nullable(Int32), `hardware_present` UInt8, `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64)) AS SELECT row_id AS snapshot_row_id, event_id AS source_event_id, event_ts AS snapshot_ts, org, orch_address, orch_uri, orch_uri_norm, cast(toUInt16OrZero(capability_key), 'Nullable(UInt16)') AS capability_id, CAST(NULL, 'Nullable(String)') AS offered_name, cast(nullIf(tupleElement(model_entry, 1), ''), 'Nullable(String)') AS model_id, cast(JSONExtractBool(tupleElement(model_entry, 2), 'warm'), 'Nullable(UInt8)') AS warm, cast(nullIf(JSONExtractInt(tupleElement(model_entry, 2), 'capacity'), 0), 'Nullable(Int32)') AS advertised_capacity, toUInt8(0) AS hardware_present, CAST(NULL, 'Nullable(String)') AS gpu_id, CAST(NULL, 'Nullable(String)') AS gpu_model_name, CAST(NULL, 'Nullable(UInt64)') AS gpu_memory_bytes_total FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, tupleElement(percap_entry, 1) AS capability_key, arrayJoin(if(models_raw IN ('', 'null', '{}'), CAST([], 'Array(Tuple(String, String))'), JSONExtractKeysAndValuesRaw(models_raw))) AS model_entry FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, percap_entry, JSONExtractRaw(tupleElement(percap_entry, 2), 'models') AS models_raw FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, arrayJoin(if(percap_raw IN ('', 'null', '{}'), CAST([], 'Array(Tuple(String, String))'), JSONExtractKeysAndValuesRaw(percap_raw))) AS percap_entry FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, JSONExtractRaw(raw_capabilities, 'capabilities', 'constraints', 'PerCapability') AS percap_raw FROM naap.normalized_network_capabilities WHERE length(JSONExtractArrayRaw(raw_capabilities, 'hardware')) = 0)))) WHERE (toUInt16OrZero(capability_key) > 0) AND (tupleElement(model_entry, 1) != '');

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_offer_inventory_store_hardware TO naap.canonical_capability_offer_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `offered_name` Nullable(String), `model_id` Nullable(String), `warm` Nullable(UInt8), `advertised_capacity` Nullable(Int32), `hardware_present` UInt8, `gpu_id` Nullable(String), `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64)) AS SELECT row_id AS snapshot_row_id, event_id AS source_event_id, event_ts AS snapshot_ts, org, orch_address, orch_uri, orch_uri_norm, CAST(NULL, 'Nullable(UInt16)') AS capability_id, cast(nullIf(JSONExtractString(hardware_json, 'pipeline'), ''), 'Nullable(String)') AS offered_name, cast(nullIf(JSONExtractString(hardware_json, 'model_id'), ''), 'Nullable(String)') AS model_id, CAST(NULL, 'Nullable(UInt8)') AS warm, CAST(NULL, 'Nullable(Int32)') AS advertised_capacity, toUInt8(1) AS hardware_present, cast(nullIf(JSONExtractString(gpu_json, 'id'), ''), 'Nullable(String)') AS gpu_id, cast(nullIf(JSONExtractString(gpu_json, 'name'), ''), 'Nullable(String)') AS gpu_model_name, cast(nullIf(JSONExtractUInt(gpu_json, 'memory_total'), 0), 'Nullable(UInt64)') AS gpu_memory_bytes_total FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, hardware_json, arrayJoin(if(gpu_info_raw IN ('', 'null', '{}', '[]'), CAST(['{}'], 'Array(String)'), if(startsWith(gpu_info_raw, '['), JSONExtractArrayRaw(gpu_info_raw), tupleElement(JSONExtractKeysAndValuesRaw(gpu_info_raw), 2)))) AS gpu_json FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, hardware_json, JSONExtractRaw(hardware_json, 'gpu_info') AS gpu_info_raw FROM (SELECT row_id, event_id, event_ts, org, orch_address, orch_uri, orch_uri_norm, arrayJoin(JSONExtractArrayRaw(raw_capabilities, 'hardware')) AS hardware_json FROM naap.normalized_network_capabilities WHERE length(JSONExtractArrayRaw(raw_capabilities, 'hardware')) > 0))) WHERE offered_name IS NOT NULL;

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_pricing_inventory_store_capability TO naap.canonical_capability_pricing_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `constraint_value` Nullable(String), `price_per_unit` Int64, `pixels_per_unit` Int64) AS SELECT row_id AS snapshot_row_id, event_id AS source_event_id, event_ts AS snapshot_ts, org, orch_address, orch_uri, orch_uri_norm, cast(toUInt16(JSONExtractUInt(price_json, 'capability')), 'Nullable(UInt16)') AS capability_id, cast(nullIf(JSONExtractString(price_json, 'constraint'), ''), 'Nullable(String)') AS constraint_value, toInt64(JSONExtractInt(price_json, 'pricePerUnit')) AS price_per_unit, toInt64(JSONExtractInt(price_json, 'pixelsPerUnit')) AS pixels_per_unit FROM naap.normalized_network_capabilities ARRAY JOIN JSONExtractArrayRaw(raw_capabilities, 'capabilities_prices') AS price_json WHERE (JSONExtractUInt(price_json, 'capability') > 0) AND (JSONExtractInt(price_json, 'pricePerUnit') > 0) AND (JSONExtractInt(price_json, 'pixelsPerUnit') > 0);

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_pricing_inventory_store_global TO naap.canonical_capability_pricing_inventory_store (`snapshot_row_id` String, `source_event_id` String, `snapshot_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_uri` String, `orch_uri_norm` String, `capability_id` Nullable(UInt16), `constraint_value` Nullable(String), `price_per_unit` Int64, `pixels_per_unit` Int64) AS SELECT row_id AS snapshot_row_id, event_id AS source_event_id, event_ts AS snapshot_ts, org, orch_address, orch_uri, orch_uri_norm, CAST(NULL, 'Nullable(UInt16)') AS capability_id, CAST(NULL, 'Nullable(String)') AS constraint_value, toInt64(JSONExtractInt(raw_capabilities, 'price_info', 'pricePerUnit')) AS price_per_unit, toInt64(JSONExtractInt(raw_capabilities, 'price_info', 'pixelsPerUnit')) AS pixels_per_unit FROM naap.normalized_network_capabilities WHERE (JSONExtractInt(raw_capabilities, 'price_info', 'pricePerUnit') > 0) AND (JSONExtractInt(raw_capabilities, 'price_info', 'pixelsPerUnit') > 0);

CREATE MATERIALIZED VIEW naap.mv_canonical_capability_snapshot_latest TO naap.canonical_capability_snapshot_latest (`org` LowCardinality(String), `orch_address` String, `orch_uri_norm` String, `snapshot_row_id` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `source_event_id` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `snapshot_ts` AggregateFunction(max, DateTime64(3, 'UTC')), `orch_name` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `orch_uri` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `version` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `raw_capabilities` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8)) AS SELECT org, orch_address, orch_uri_norm, argMaxIfState(row_id, event_ts, toUInt8(row_id != '')) AS snapshot_row_id, argMaxIfState(event_id, event_ts, toUInt8(event_id != '')) AS source_event_id, maxState(event_ts) AS snapshot_ts, argMaxIfState(orch_name, event_ts, toUInt8(orch_name != '')) AS orch_name, argMaxIfState(orch_uri, event_ts, toUInt8(orch_uri != '')) AS orch_uri, argMaxIfState(version, event_ts, toUInt8(version != '')) AS version, argMaxIfState(raw_capabilities, event_ts, toUInt8(raw_capabilities != '')) AS raw_capabilities FROM naap.normalized_network_capabilities WHERE orch_address != '' GROUP BY org, orch_address, orch_uri_norm;

CREATE MATERIALIZED VIEW naap.mv_discovery_latency_hourly TO naap.agg_discovery_latency_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `orch_address` String, `latency_ms_sum` UInt64, `sample_count` UInt8) AS SELECT toStartOfHour(event_ts) AS hour, org, lower(JSONExtractString(orch_json, 'address')) AS orch_address, toUInt64OrDefault(JSONExtractString(orch_json, 'latency_ms')) AS latency_ms_sum, 1 AS sample_count FROM (SELECT event_ts, org, arrayJoin(JSONExtractArrayRaw(data)) AS orch_json FROM naap.accepted_raw_events WHERE (event_type = 'discovery_results') AND (data NOT IN ('', '[]', 'null'))) WHERE JSONExtractString(orch_json, 'address') != '';

CREATE MATERIALIZED VIEW naap.mv_fps_hourly TO naap.agg_fps_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `orch_address` String, `pipeline` String, `inference_fps_sum` Float64, `input_fps_sum` Float64, `sample_count` UInt8) AS WITH lower(JSONExtractString(data, 'orchestrator_info', 'address')) AS derived_orch_address, JSONExtractString(data, 'pipeline') AS derived_pipeline, JSONExtractFloat(data, 'inference_status', 'fps') AS derived_inference_fps, JSONExtractFloat(data, 'input_status', 'fps') AS derived_input_fps SELECT toStartOfHour(event_ts) AS hour, org, derived_orch_address AS orch_address, derived_pipeline AS pipeline, derived_inference_fps AS inference_fps_sum, derived_input_fps AS input_fps_sum, 1 AS sample_count FROM naap.accepted_raw_events WHERE (event_type = 'ai_stream_status') AND (derived_inference_fps > 0);

CREATE MATERIALIZED VIEW naap.mv_ingest_network_events_accepted TO naap.accepted_raw_events (`event_id` String, `event_type` String, `event_subtype` String, `event_ts` DateTime64(3), `org` String, `gateway` String, `data` String, `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String), `ingested_at` DateTime64(3)) AS WITH if(type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), '') AS derived_event_subtype, nullIf(JSONExtractString(data, 'schema_version'), '') AS derived_schema_version SELECT id AS event_id, type AS event_type, derived_event_subtype AS event_subtype, parseDateTime64BestEffort(timestamp) AS event_ts, 'daydream' AS org, gateway, data, _topic AS source_topic, toInt32(_partition) AS source_partition, toInt64(_offset) AS source_offset, hex(MD5(data)) AS payload_hash, derived_schema_version AS schema_version, now64() AS ingested_at FROM naap.kafka_network_events WHERE (id != '') AND (type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment')) AND ((type != 'stream_trace') OR (derived_event_subtype IN ('gateway_receive_stream_request', 'gateway_ingest_stream_closed', 'gateway_send_first_ingest_segment', 'gateway_receive_first_processed_segment', 'gateway_receive_few_processed_segments', 'gateway_receive_first_data_segment', 'gateway_no_orchestrators_available', 'orchestrator_swap', 'runner_receive_first_ingest_segment', 'runner_send_first_processed_segment')));

CREATE MATERIALIZED VIEW naap.mv_ingest_network_events_ignored TO naap.ignored_raw_events (`event_id` String, `event_type` String, `event_subtype` String, `ignore_reason` String, `event_ts` DateTime64(3), `org` String, `gateway` String, `data` String, `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String), `ingested_at` DateTime64(3)) AS WITH if(type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), '') AS derived_event_subtype, lowerUTF8(JSONExtractString(data, 'client_source')) AS derived_client_source, nullIf(JSONExtractString(data, 'schema_version'), '') AS derived_schema_version SELECT id AS event_id, type AS event_type, derived_event_subtype AS event_subtype, multiIf(type NOT IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment'), 'unsupported_event_family', (type = 'stream_trace') AND startsWith(lowerUTF8(derived_event_subtype), 'app_'), 'ignored_stream_trace_non_core_app', (type = 'stream_trace') AND (derived_client_source = 'scope') AND (derived_event_subtype IN ('stream_heartbeat', 'pipeline_load_start', 'pipeline_loaded', 'session_created', 'stream_started', 'playback_ready', 'session_closed', 'stream_stopped', 'pipeline_unloaded', 'websocket_connected', 'websocket_disconnected', 'error')), 'ignored_stream_trace_scope_client_noise', type = 'stream_trace', 'unsupported_stream_trace_type', 'malformed_or_invalid_payload') AS ignore_reason, parseDateTime64BestEffort(timestamp) AS event_ts, 'daydream' AS org, gateway, data, _topic AS source_topic, toInt32(_partition) AS source_partition, toInt64(_offset) AS source_offset, hex(MD5(data)) AS payload_hash, derived_schema_version AS schema_version, now64() AS ingested_at FROM naap.kafka_network_events WHERE (id != '') AND ((type NOT IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment')) OR ((type = 'stream_trace') AND (derived_event_subtype NOT IN ('gateway_receive_stream_request', 'gateway_ingest_stream_closed', 'gateway_send_first_ingest_segment', 'gateway_receive_first_processed_segment', 'gateway_receive_few_processed_segments', 'gateway_receive_first_data_segment', 'gateway_no_orchestrators_available', 'orchestrator_swap', 'runner_receive_first_ingest_segment', 'runner_send_first_processed_segment'))));

CREATE MATERIALIZED VIEW naap.mv_ingest_streaming_events_accepted TO naap.accepted_raw_events (`event_id` String, `event_type` String, `event_subtype` String, `event_ts` DateTime64(3), `org` String, `gateway` String, `data` String, `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String), `ingested_at` DateTime64(3)) AS WITH if(type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), '') AS derived_event_subtype, nullIf(JSONExtractString(data, 'schema_version'), '') AS derived_schema_version SELECT id AS event_id, type AS event_type, derived_event_subtype AS event_subtype, parseDateTime64BestEffort(timestamp) AS event_ts, 'cloudspe' AS org, gateway, data, _topic AS source_topic, toInt32(_partition) AS source_partition, toInt64(_offset) AS source_offset, hex(MD5(data)) AS payload_hash, derived_schema_version AS schema_version, now64() AS ingested_at FROM naap.kafka_streaming_events WHERE (id != '') AND (type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment')) AND ((type != 'stream_trace') OR (derived_event_subtype IN ('gateway_receive_stream_request', 'gateway_ingest_stream_closed', 'gateway_send_first_ingest_segment', 'gateway_receive_first_processed_segment', 'gateway_receive_few_processed_segments', 'gateway_receive_first_data_segment', 'gateway_no_orchestrators_available', 'orchestrator_swap', 'runner_receive_first_ingest_segment', 'runner_send_first_processed_segment')));

CREATE MATERIALIZED VIEW naap.mv_ingest_streaming_events_ignored TO naap.ignored_raw_events (`event_id` String, `event_type` String, `event_subtype` String, `ignore_reason` String, `event_ts` DateTime64(3), `org` String, `gateway` String, `data` String, `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String), `ingested_at` DateTime64(3)) AS WITH if(type IN ('stream_trace', 'ai_stream_status', 'ai_stream_events'), JSONExtractString(data, 'type'), '') AS derived_event_subtype, lowerUTF8(JSONExtractString(data, 'client_source')) AS derived_client_source, nullIf(JSONExtractString(data, 'schema_version'), '') AS derived_schema_version SELECT id AS event_id, type AS event_type, derived_event_subtype AS event_subtype, multiIf(type NOT IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment'), 'unsupported_event_family', (type = 'stream_trace') AND startsWith(lowerUTF8(derived_event_subtype), 'app_'), 'ignored_stream_trace_non_core_app', (type = 'stream_trace') AND (derived_client_source = 'scope') AND (derived_event_subtype IN ('stream_heartbeat', 'pipeline_load_start', 'pipeline_loaded', 'session_created', 'stream_started', 'playback_ready', 'session_closed', 'stream_stopped', 'pipeline_unloaded', 'websocket_connected', 'websocket_disconnected', 'error')), 'ignored_stream_trace_scope_client_noise', type = 'stream_trace', 'unsupported_stream_trace_type', 'malformed_or_invalid_payload') AS ignore_reason, parseDateTime64BestEffort(timestamp) AS event_ts, 'cloudspe' AS org, gateway, data, _topic AS source_topic, toInt32(_partition) AS source_partition, toInt64(_offset) AS source_offset, hex(MD5(data)) AS payload_hash, derived_schema_version AS schema_version, now64() AS ingested_at FROM naap.kafka_streaming_events WHERE (id != '') AND ((type NOT IN ('stream_trace', 'ai_stream_status', 'ai_stream_events', 'stream_ingest_metrics', 'network_capabilities', 'discovery_results', 'create_new_payment')) OR ((type = 'stream_trace') AND (derived_event_subtype NOT IN ('gateway_receive_stream_request', 'gateway_ingest_stream_closed', 'gateway_send_first_ingest_segment', 'gateway_receive_first_processed_segment', 'gateway_receive_few_processed_segments', 'gateway_receive_first_data_segment', 'gateway_no_orchestrators_available', 'orchestrator_swap', 'runner_receive_first_ingest_segment', 'runner_send_first_processed_segment'))));

CREATE MATERIALIZED VIEW naap.mv_normalized_ai_stream_events TO naap.normalized_ai_stream_events (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `raw_pipeline_hint` String, `event_name` LowCardinality(String), `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `message` String, `data` String) AS SELECT event_id, event_ts, org, gateway, JSONExtractString(data, 'stream_id') AS stream_id, JSONExtractString(data, 'request_id') AS request_id, multiIf(org = '', '', (JSONExtractString(data, 'stream_id') != '') AND (JSONExtractString(data, 'request_id') != ''), concat(org, '|', JSONExtractString(data, 'stream_id'), '|', JSONExtractString(data, 'request_id')), JSONExtractString(data, 'stream_id') != '', concat(org, '|', JSONExtractString(data, 'stream_id'), '|_missing_request'), JSONExtractString(data, 'request_id') != '', concat(org, '|_missing_stream|', JSONExtractString(data, 'request_id')), '') AS canonical_session_key, JSONExtractString(data, 'pipeline') AS raw_pipeline_hint, event_subtype AS event_name, lower(JSONExtractString(data, 'orchestrator_info', 'address')) AS orch_raw_address, JSONExtractString(data, 'orchestrator_info', 'url') AS orch_url, lower(JSONExtractString(data, 'orchestrator_info', 'url')) AS orch_url_norm, JSONExtractString(data, 'message') AS message, data FROM naap.accepted_raw_events WHERE event_type = 'ai_stream_events';

CREATE MATERIALIZED VIEW naap.mv_normalized_ai_stream_status TO naap.normalized_ai_stream_status (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `raw_pipeline_hint` String, `state` String, `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Float64, `start_time` Nullable(DateTime64(3)), `restart_count` UInt64, `last_error` String, `last_error_ts` DateTime64(3), `data` String) AS WITH JSONExtractString(data, 'stream_id') AS derived_stream_id, JSONExtractString(data, 'request_id') AS derived_request_id, JSONExtractString(data, 'pipeline') AS derived_pipeline, lower(JSONExtractString(data, 'orchestrator_info', 'address')) AS derived_orch_address, JSONExtractString(data, 'orchestrator_info', 'url') AS derived_orch_url, JSONExtractFloat(data, 'inference_status', 'fps') AS derived_output_fps, JSONExtractFloat(data, 'input_status', 'fps') AS derived_input_fps, JSONExtractFloat(data, 'inference_status', 'latency_ms') AS derived_e2e_latency_ms, JSONExtractString(data, 'state') AS derived_state SELECT event_id, event_ts, org, gateway, derived_stream_id AS stream_id, derived_request_id AS request_id, multiIf(org = '', '', (derived_stream_id != '') AND (derived_request_id != ''), concat(org, '|', derived_stream_id, '|', derived_request_id), derived_stream_id != '', concat(org, '|', derived_stream_id, '|_missing_request'), derived_request_id != '', concat(org, '|_missing_stream|', derived_request_id), '') AS canonical_session_key, derived_pipeline AS raw_pipeline_hint, derived_state AS state, derived_orch_address AS orch_raw_address, derived_orch_url AS orch_url, lower(derived_orch_url) AS orch_url_norm, derived_output_fps AS output_fps, derived_input_fps AS input_fps, derived_e2e_latency_ms AS e2e_latency_ms, parseDateTime64BestEffortOrNull(JSONExtractString(data, 'start_time')) AS start_time, JSONExtractUInt(data, 'inference_status', 'restart_count') AS restart_count, JSONExtractString(data, 'inference_status', 'last_error') AS last_error, coalesce(parseDateTime64BestEffortOrNull(JSONExtractString(data, 'inference_status', 'last_error_time')), toDateTime64(0, 3, 'UTC')) AS last_error_ts, data FROM naap.accepted_raw_events WHERE event_type = 'ai_stream_status';

CREATE MATERIALIZED VIEW naap.mv_normalized_network_capabilities TO naap.normalized_network_capabilities (`row_id` String, `event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `orch_address` String, `orch_name` String, `orch_uri` String, `orch_uri_norm` String, `version` String, `raw_capabilities` String) AS SELECT concat(event_id, '#', lower(JSONExtractString(orch_json, 'address'))) AS row_id, event_id, event_ts, org, lower(JSONExtractString(orch_json, 'address')) AS orch_address, if(JSONExtractString(orch_json, 'local_address') != '', JSONExtractString(orch_json, 'local_address'), JSONExtractString(orch_json, 'address')) AS orch_name, coalesce(nullIf(JSONExtractString(orch_json, 'orch_uri'), ''), JSONExtractString(orch_json, 'uri')) AS orch_uri, lower(coalesce(nullIf(JSONExtractString(orch_json, 'orch_uri'), ''), JSONExtractString(orch_json, 'uri'))) AS orch_uri_norm, JSONExtractString(orch_json, 'version') AS version, orch_json AS raw_capabilities FROM (SELECT event_id, event_ts, org, arrayJoin(JSONExtractArrayRaw(data)) AS orch_json FROM naap.accepted_raw_events WHERE (event_type = 'network_capabilities') AND (data NOT IN ('', '[]', 'null'))) WHERE orch_address != '';

CREATE MATERIALIZED VIEW naap.mv_normalized_session_attribution_input_from_events TO naap.normalized_session_attribution_input_latest_store (`org` LowCardinality(String), `canonical_session_key` String, `status_pipeline_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `event_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_pipeline_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_raw_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC')), `swap_count_state` AggregateFunction(sum, UInt64)) AS SELECT org, canonical_session_key, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS status_pipeline_state, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS event_pipeline_hint_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS trace_pipeline_id_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS trace_raw_pipeline_hint_state, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS last_seen_state, sumState(toUInt64(0)) AS swap_count_state FROM naap.normalized_ai_stream_events WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_attribution_input_from_status TO naap.normalized_session_attribution_input_latest_store (`org` LowCardinality(String), `canonical_session_key` String, `status_pipeline_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `event_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_pipeline_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_raw_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC')), `swap_count_state` AggregateFunction(sum, UInt64)) AS SELECT org, canonical_session_key, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS status_pipeline_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS event_pipeline_hint_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS trace_pipeline_id_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS trace_raw_pipeline_hint_state, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS last_seen_state, sumState(toUInt64(0)) AS swap_count_state FROM naap.normalized_ai_stream_status WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_attribution_input_from_trace TO naap.normalized_session_attribution_input_latest_store (`org` LowCardinality(String), `canonical_session_key` String, `status_pipeline_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `event_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_pipeline_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `trace_raw_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC')), `swap_count_state` AggregateFunction(sum, UInt64)) AS SELECT org, canonical_session_key, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS status_pipeline_state, argMaxIfState(CAST('', 'String'), event_ts, toUInt8(0)) AS event_pipeline_hint_state, argMaxIfState(pipeline_id, event_ts, toUInt8(pipeline_id != '')) AS trace_pipeline_id_state, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS trace_raw_pipeline_hint_state, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS last_seen_state, sumState(toUInt64(trace_type = 'orchestrator_swap')) AS swap_count_state FROM naap.normalized_stream_trace WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_event_rollup_latest TO naap.normalized_session_event_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `event_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `any_event_message_count_state` AggregateFunction(sum, UInt64), `event_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS event_pipeline_hint_state, sumState(toUInt64(message != '')) AS any_event_message_count_state, maxState(event_ts) AS event_last_seen_state FROM naap.normalized_ai_stream_events WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_orch_observation_from_events TO naap.normalized_session_orchestrator_observation_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observation_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS observation_last_seen_state FROM naap.normalized_ai_stream_events WHERE (canonical_session_key != '') AND ((orch_raw_address != '') OR (orch_url != '')) GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_orch_observation_from_status TO naap.normalized_session_orchestrator_observation_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observation_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS observation_last_seen_state FROM naap.normalized_ai_stream_status WHERE (canonical_session_key != '') AND ((orch_raw_address != '') OR (orch_url != '')) GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_orch_observation_from_trace TO naap.normalized_session_orchestrator_observation_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `observed_orch_address_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_url_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `observed_orch_address_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observed_orch_url_uniq` AggregateFunction(uniqExactIf, String, UInt8), `observation_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(orch_raw_address, event_ts, toUInt8(orch_raw_address != '')) AS observed_orch_address_state, argMaxIfState(orch_url, event_ts, toUInt8(orch_url != '')) AS observed_orch_url_state, uniqExactIfState(orch_raw_address, toUInt8(orch_raw_address != '')) AS observed_orch_address_uniq, uniqExactIfState(lower(orch_url), toUInt8(orch_url != '')) AS observed_orch_url_uniq, maxState(event_ts) AS observation_last_seen_state FROM naap.normalized_stream_trace WHERE (canonical_session_key != '') AND ((orch_raw_address != '') OR (orch_url != '')) GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_status_hour_rollup TO naap.normalized_session_status_hour_rollup (`org` LowCardinality(String), `canonical_session_key` String, `hour` DateTime('UTC'), `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `status_samples_state` AggregateFunction(sum, UInt64), `fps_positive_samples_state` AggregateFunction(sum, UInt64), `running_state_samples_state` AggregateFunction(sum, UInt64), `degraded_input_samples_state` AggregateFunction(sum, UInt64), `degraded_inference_samples_state` AggregateFunction(sum, UInt64), `error_samples_state` AggregateFunction(sum, UInt64), `output_fps_sum_state` AggregateFunction(sum, Float64), `input_fps_sum_state` AggregateFunction(sum, Float64), `e2e_latency_sum_state` AggregateFunction(sum, Float64), `e2e_latency_count_state` AggregateFunction(sum, UInt64)) AS SELECT org, canonical_session_key, toStartOfHour(event_ts) AS hour, argMaxIfState(stream_id, event_ts, toUInt8(stream_id != '')) AS stream_id_state, argMaxIfState(request_id, event_ts, toUInt8(request_id != '')) AS request_id_state, sumState(toUInt64(1)) AS status_samples_state, sumState(toUInt64(output_fps > 0)) AS fps_positive_samples_state, sumState(toUInt64(state IN ('ONLINE', 'DEGRADED_INPUT', 'DEGRADED_INFERENCE'))) AS running_state_samples_state, sumState(toUInt64(state = 'DEGRADED_INPUT')) AS degraded_input_samples_state, sumState(toUInt64(state = 'DEGRADED_INFERENCE')) AS degraded_inference_samples_state, sumState(toUInt64(last_error NOT IN ('', 'null'))) AS error_samples_state, sumState(output_fps) AS output_fps_sum_state, sumState(input_fps) AS input_fps_sum_state, sumState(if(e2e_latency_ms > 0, e2e_latency_ms, 0.)) AS e2e_latency_sum_state, sumState(toUInt64(e2e_latency_ms > 0)) AS e2e_latency_count_state FROM naap.normalized_ai_stream_status WHERE canonical_session_key != '' GROUP BY org, canonical_session_key, hour;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_status_rollup_latest TO naap.normalized_session_status_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `canonical_pipeline_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `start_time_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `restart_seen_count_state` AggregateFunction(sum, UInt64), `error_seen_count_state` AggregateFunction(sum, UInt64), `degraded_input_seen_count_state` AggregateFunction(sum, UInt64), `degraded_inference_seen_count_state` AggregateFunction(sum, UInt64), `status_sample_count_state` AggregateFunction(sum, UInt64), `status_error_sample_count_state` AggregateFunction(sum, UInt64), `online_seen_count_state` AggregateFunction(sum, UInt64), `positive_output_seen_count_state` AggregateFunction(sum, UInt64), `running_state_samples_count_state` AggregateFunction(sum, UInt64), `status_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(stream_id, event_ts, toUInt8(stream_id != '')) AS stream_id_state, argMaxIfState(request_id, event_ts, toUInt8(request_id != '')) AS request_id_state, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS canonical_pipeline_state, minIfState(coalesce(start_time, toDateTime64(0, 3, 'UTC')), toUInt8(start_time IS NOT NULL)) AS start_time_state, sumState(toUInt64(restart_count > 0)) AS restart_seen_count_state, sumState(toUInt64(last_error NOT IN ('', 'null'))) AS error_seen_count_state, sumState(toUInt64(state = 'DEGRADED_INPUT')) AS degraded_input_seen_count_state, sumState(toUInt64(state = 'DEGRADED_INFERENCE')) AS degraded_inference_seen_count_state, sumState(toUInt64(1)) AS status_sample_count_state, sumState(toUInt64(last_error NOT IN ('', 'null'))) AS status_error_sample_count_state, sumState(toUInt64(state = 'ONLINE')) AS online_seen_count_state, sumState(toUInt64(output_fps > 0)) AS positive_output_seen_count_state, sumState(toUInt64(state IN ('ONLINE', 'DEGRADED_INPUT', 'DEGRADED_INFERENCE'))) AS running_state_samples_count_state, maxState(event_ts) AS status_last_seen_state FROM naap.normalized_ai_stream_status WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_session_trace_rollup_latest TO naap.normalized_session_trace_rollup_latest (`org` LowCardinality(String), `canonical_session_key` String, `stream_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `request_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `pipeline_id_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `raw_pipeline_hint_state` AggregateFunction(argMaxIf, String, DateTime64(3, 'UTC'), UInt8), `started_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `first_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `few_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `first_ingest_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `runner_first_processed_at_state` AggregateFunction(minIf, DateTime64(3, 'UTC'), UInt8), `started_count_state` AggregateFunction(sum, UInt64), `playable_seen_count_state` AggregateFunction(sum, UInt64), `no_orch_count_state` AggregateFunction(sum, UInt64), `completed_count_state` AggregateFunction(sum, UInt64), `swap_count_state` AggregateFunction(sum, UInt64), `trace_last_seen_state` AggregateFunction(max, DateTime64(3, 'UTC'))) AS SELECT org, canonical_session_key, argMaxIfState(stream_id, event_ts, toUInt8(stream_id != '')) AS stream_id_state, argMaxIfState(request_id, event_ts, toUInt8(request_id != '')) AS request_id_state, argMaxIfState(pipeline_id, event_ts, toUInt8(pipeline_id != '')) AS pipeline_id_state, argMaxIfState(raw_pipeline_hint, event_ts, toUInt8(raw_pipeline_hint != '')) AS raw_pipeline_hint_state, minIfState(event_ts, toUInt8(trace_type = 'gateway_receive_stream_request')) AS started_at_state, minIfState(event_ts, toUInt8(trace_type = 'gateway_receive_first_processed_segment')) AS first_processed_at_state, minIfState(event_ts, toUInt8(trace_type = 'gateway_receive_few_processed_segments')) AS few_processed_at_state, minIfState(event_ts, toUInt8(trace_type = 'gateway_send_first_ingest_segment')) AS first_ingest_at_state, minIfState(event_ts, toUInt8(trace_type = 'runner_send_first_processed_segment')) AS runner_first_processed_at_state, sumState(toUInt64(trace_type = 'gateway_receive_stream_request')) AS started_count_state, sumState(toUInt64(trace_type = 'gateway_receive_few_processed_segments')) AS playable_seen_count_state, sumState(toUInt64(trace_type = 'gateway_no_orchestrators_available')) AS no_orch_count_state, sumState(toUInt64(trace_type = 'gateway_ingest_stream_closed')) AS completed_count_state, sumState(toUInt64(trace_type = 'orchestrator_swap')) AS swap_count_state, maxState(event_ts) AS trace_last_seen_state FROM naap.normalized_stream_trace WHERE canonical_session_key != '' GROUP BY org, canonical_session_key;

CREATE MATERIALIZED VIEW naap.mv_normalized_stream_trace TO naap.normalized_stream_trace (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `stream_id` String, `request_id` String, `canonical_session_key` String, `trace_type` LowCardinality(String), `raw_pipeline_hint` String, `pipeline_id` String, `orch_raw_address` String, `orch_url` String, `orch_url_norm` String, `message` String, `data` String) AS SELECT event_id, event_ts, org, gateway, JSONExtractString(data, 'stream_id') AS stream_id, JSONExtractString(data, 'request_id') AS request_id, multiIf(org = '', '', (JSONExtractString(data, 'stream_id') != '') AND (JSONExtractString(data, 'request_id') != ''), concat(org, '|', JSONExtractString(data, 'stream_id'), '|', JSONExtractString(data, 'request_id')), JSONExtractString(data, 'stream_id') != '', concat(org, '|', JSONExtractString(data, 'stream_id'), '|_missing_request'), JSONExtractString(data, 'request_id') != '', concat(org, '|_missing_stream|', JSONExtractString(data, 'request_id')), '') AS canonical_session_key, event_subtype AS trace_type, JSONExtractString(data, 'pipeline') AS raw_pipeline_hint, JSONExtractString(data, 'pipeline_id') AS pipeline_id, lower(JSONExtractString(data, 'orchestrator_info', 'address')) AS orch_raw_address, JSONExtractString(data, 'orchestrator_info', 'url') AS orch_url, lower(JSONExtractString(data, 'orchestrator_info', 'url')) AS orch_url_norm, JSONExtractString(data, 'message') AS message, data FROM naap.accepted_raw_events WHERE event_type = 'stream_trace';

CREATE MATERIALIZED VIEW naap.mv_orch_reliability_hourly TO naap.agg_orch_reliability_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `orch_address` String, `ai_stream_count` UInt8, `degraded_count` UInt64, `restart_count` UInt64, `error_count` UInt64) AS SELECT toStartOfHour(e.event_ts) AS hour, e.org, lower(ifNull(o.orch_address, '')) AS orch_address, 1 AS ai_stream_count, toUInt64(JSONExtractString(e.data, 'state') IN ('DEGRADED_INFERENCE', 'DEGRADED_INPUT')) AS degraded_count, toUInt64(JSONExtractUInt(e.data, 'inference_status', 'restart_count') > 0) AS restart_count, toUInt64(JSONExtractString(e.data, 'inference_status', 'last_error') NOT IN ('', 'null')) AS error_count FROM naap.accepted_raw_events AS e LEFT JOIN (SELECT uri, orch_address FROM naap.agg_orch_state FINAL) AS o ON o.uri = JSONExtractString(e.data, 'orchestrator_info', 'url') WHERE (e.event_type = 'ai_stream_status') AND (JSONExtractString(e.data, 'orchestrator_info', 'url') != '');

CREATE MATERIALIZED VIEW naap.mv_orch_state TO naap.agg_orch_state (`orch_address` String, `org` LowCardinality(String), `name` String, `uri` String, `version` String, `last_seen` DateTime64(3, 'UTC'), `raw_capabilities` String) AS SELECT lower(JSONExtractString(orch_json, 'address')) AS orch_address, org, if(JSONExtractString(orch_json, 'local_address') != '', JSONExtractString(orch_json, 'local_address'), JSONExtractString(orch_json, 'address')) AS name, JSONExtractString(orch_json, 'orch_uri') AS uri, JSONExtractString(orch_json, 'version') AS version, event_ts AS last_seen, orch_json AS raw_capabilities FROM (SELECT event_ts, org, arrayJoin(JSONExtractArrayRaw(data)) AS orch_json FROM naap.accepted_raw_events WHERE (event_type = 'network_capabilities') AND (data NOT IN ('', '[]', 'null'))) WHERE JSONExtractString(orch_json, 'address') != '';

CREATE MATERIALIZED VIEW naap.mv_payment_hourly TO naap.agg_payment_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `pipeline` String, `orch_address` String, `total_wei` UInt64, `event_count` UInt8) AS SELECT toStartOfHour(event_ts) AS hour, org, replaceRegexpOne(JSONExtractString(data, 'manifestID'), '^[0-9]+_', '') AS pipeline, lower(JSONExtractString(data, 'recipient')) AS orch_address, toUInt64OrDefault(trimRight(replaceAll(JSONExtractString(data, 'faceValue'), ' WEI', ''))) AS total_wei, 1 AS event_count FROM naap.accepted_raw_events WHERE (event_type = 'create_new_payment') AND (JSONExtractString(data, 'recipient') != '');

CREATE MATERIALIZED VIEW naap.mv_stream_hourly TO naap.agg_stream_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `pipeline` String, `started` UInt64, `completed` UInt64, `no_orch` UInt64, `orch_swap` UInt64) AS SELECT toStartOfHour(event_ts) AS hour, org, '' AS pipeline, countIf(JSONExtractString(data, 'type') = 'gateway_receive_stream_request') AS started, countIf(JSONExtractString(data, 'type') = 'gateway_ingest_stream_closed') AS completed, countIf(JSONExtractString(data, 'type') = 'gateway_no_orchestrators_available') AS no_orch, countIf(JSONExtractString(data, 'type') = 'orchestrator_swap') AS orch_swap FROM naap.accepted_raw_events WHERE event_type = 'stream_trace' GROUP BY hour, org, pipeline;

CREATE MATERIALIZED VIEW naap.mv_stream_state TO naap.agg_stream_state (`stream_id` String, `org` LowCardinality(String), `pipeline` String, `state` String, `last_seen` DateTime64(3, 'UTC'), `started_at` DateTime64(3, 'UTC'), `is_closed` UInt8, `has_failure` UInt8, `orch_address` String) AS SELECT JSONExtractString(e.data, 'stream_id') AS stream_id, e.org, if(e.event_type = 'ai_stream_status', JSONExtractString(e.data, 'pipeline'), '') AS pipeline, if(e.event_type = 'ai_stream_status', JSONExtractString(e.data, 'state'), 'UNKNOWN') AS state, e.event_ts AS last_seen, if((e.event_type = 'stream_trace') AND (JSONExtractString(e.data, 'type') = 'gateway_receive_stream_request'), e.event_ts, toDateTime64(0, 3, 'UTC')) AS started_at, if((e.event_type = 'stream_trace') AND (JSONExtractString(e.data, 'type') = 'gateway_ingest_stream_closed'), 1, 0) AS is_closed, if((e.event_type = 'stream_trace') AND (JSONExtractString(e.data, 'type') = 'gateway_no_orchestrators_available'), 1, 0) AS has_failure, if(e.event_type = 'ai_stream_status', lower(ifNull(o.orch_address, '')), '') AS orch_address FROM naap.accepted_raw_events AS e LEFT JOIN (SELECT uri, orch_address FROM naap.agg_orch_state FINAL) AS o ON o.uri = JSONExtractString(e.data, 'orchestrator_info', 'url') WHERE (e.event_type IN ('stream_trace', 'ai_stream_status')) AND (JSONExtractString(e.data, 'stream_id') != '');

CREATE MATERIALIZED VIEW naap.mv_stream_status_samples TO naap.agg_stream_status_samples (`sample_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `stream_id` String, `gateway` String, `orch_address` String, `pipeline` String, `state` String, `output_fps` Float64, `input_fps` Float64, `e2e_latency_ms` Float64, `is_attributed` UInt8) AS WITH JSONExtractString(data, 'stream_id') AS derived_stream_id, JSONExtractString(data, 'pipeline') AS derived_pipeline, JSONExtractString(data, 'orchestrator_info', 'url') AS derived_orch_url, lower(JSONExtractString(data, 'orchestrator_info', 'address')) AS derived_orch_address, JSONExtractString(data, 'inference_status', 'state') AS derived_inference_state, JSONExtractString(data, 'input_status', 'state') AS derived_input_state, JSONExtractFloat(data, 'inference_status', 'fps') AS derived_output_fps, JSONExtractFloat(data, 'input_status', 'fps') AS derived_input_fps, JSONExtractFloat(data, 'inference_status', 'latency_ms') AS derived_e2e_latency_ms SELECT event_ts AS sample_ts, org, derived_stream_id AS stream_id, gateway, ifNull(o.orch_address, derived_orch_address) AS orch_address, derived_pipeline AS pipeline, multiIf(derived_inference_state = 'Running', 'ONLINE', derived_inference_state = 'Idle', 'LOADING', derived_input_state = 'Degraded', 'DEGRADED_INPUT', derived_inference_state = 'Degraded', 'DEGRADED_INFERENCE', 'UNKNOWN') AS state, derived_output_fps AS output_fps, derived_input_fps AS input_fps, derived_e2e_latency_ms AS e2e_latency_ms, toUInt8(ifNull(o.orch_address, '') != '') AS is_attributed FROM naap.accepted_raw_events LEFT JOIN (SELECT uri, orch_address FROM naap.agg_orch_state FINAL) AS o ON o.uri = derived_orch_url WHERE (event_type = 'ai_stream_status') AND (derived_stream_id != '');

CREATE MATERIALIZED VIEW naap.mv_webrtc_hourly TO naap.agg_webrtc_hourly (`hour` DateTime('UTC'), `org` LowCardinality(String), `stream_id` String, `video_jitter_sum` Float64, `video_packets_lost` UInt64, `video_packets_recv` UInt64, `audio_jitter_sum` Float64, `audio_packets_lost` UInt64, `audio_packets_recv` UInt64, `sample_count` UInt8, `quality_good` UInt64, `quality_fair` UInt64, `quality_poor` UInt64) AS WITH JSONExtractArrayRaw(data, 'stats', 'track_stats') AS tracks, arrayFirst(x -> (JSONExtractString(x, 'type') = 'video'), tracks) AS video_track, arrayFirst(x -> (JSONExtractString(x, 'type') = 'audio'), tracks) AS audio_track SELECT toStartOfHour(event_ts) AS hour, org, JSONExtractString(data, 'stream_id') AS stream_id, if(video_track != '', JSONExtractFloat(video_track, 'jitter'), 0.) AS video_jitter_sum, if(video_track != '', toUInt64OrDefault(toString(JSONExtractUInt(video_track, 'packets_lost'))), 0) AS video_packets_lost, if(video_track != '', toUInt64OrDefault(toString(JSONExtractUInt(video_track, 'packets_received'))), 0) AS video_packets_recv, if(audio_track != '', JSONExtractFloat(audio_track, 'jitter'), 0.) AS audio_jitter_sum, if(audio_track != '', toUInt64OrDefault(toString(JSONExtractUInt(audio_track, 'packets_lost'))), 0) AS audio_packets_lost, if(audio_track != '', toUInt64OrDefault(toString(JSONExtractUInt(audio_track, 'packets_received'))), 0) AS audio_packets_recv, 1 AS sample_count, toUInt64(JSONExtractString(data, 'stats', 'conn_quality') = 'good') AS quality_good, toUInt64(JSONExtractString(data, 'stats', 'conn_quality') = 'fair') AS quality_fair, toUInt64(JSONExtractString(data, 'stats', 'conn_quality') = 'poor') AS quality_poor FROM naap.accepted_raw_events WHERE event_type = 'stream_ingest_metrics';

CREATE VIEW naap.ignored_raw_event_diagnostics (`event_id` String, `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `event_type` LowCardinality(String), `event_subtype` LowCardinality(String), `ignored_reason` LowCardinality(String), `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String)) AS SELECT event_id, event_ts, org, event_type, event_subtype, ignore_reason AS ignored_reason, source_topic, source_partition, source_offset, payload_hash, schema_version FROM naap.ignored_raw_events;

CREATE VIEW naap.raw_events (`event_id` String, `event_type` LowCardinality(String), `event_subtype` LowCardinality(String), `event_ts` DateTime64(3, 'UTC'), `org` LowCardinality(String), `gateway` String, `data` String, `source_topic` LowCardinality(String), `source_partition` Int32, `source_offset` Int64, `payload_hash` String, `schema_version` Nullable(String), `ingested_at` DateTime64(3, 'UTC')) AS SELECT * FROM naap.accepted_raw_events;

CREATE TABLE IF NOT EXISTS naap.capability_catalog (`capability_id` UInt16, `capability_name` String, `capability_family` String, `canonical_pipeline` Nullable(String), `constraint_kind` String, `supports_stream` UInt8, `supports_request` UInt8) ENGINE = MergeTree ORDER BY capability_id;

INSERT INTO naap.capability_catalog (capability_id, capability_name, capability_family, canonical_pipeline, constraint_kind, supports_stream, supports_request) VALUES (27, 'text-to-image', 'builtin', 'text-to-image', 'model_id', 0, 1), (28, 'image-to-image', 'builtin', 'image-to-image', 'model_id', 0, 1), (29, 'image-to-video', 'builtin', 'image-to-video', 'model_id', 0, 1), (30, 'upscale', 'builtin', 'upscale', 'model_id', 0, 1), (31, 'audio-to-text', 'builtin', 'audio-to-text', 'model_id', 0, 1), (32, 'segment-anything-2', 'builtin', 'segment-anything-2', 'model_id', 0, 1), (33, 'llm', 'builtin', 'llm', 'model_id', 0, 1), (34, 'image-to-text', 'builtin', 'image-to-text', 'model_id', 0, 1), (35, 'live-video-to-video', 'builtin', 'live-video-to-video', 'model_id', 1, 0), (36, 'text-to-speech', 'builtin', 'text-to-speech', 'model_id', 0, 1), (37, 'byoc', 'byoc', NULL, 'external_capability_name', 1, 1);
